import {{ Injectable }} from '@nestjs/common';
import {{ WebhookService }} from './models/webhook.model';
import {{ WebhookServiceRepository }} from './repositories/webhook.repository';

@Injectable()
export class WebhookServiceService {{
  constructor(
    private readonly repository: WebhookServiceRepository,
  ) {{}}

  async findAll(): Promise<WebhookService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<WebhookService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<WebhookService>): Promise<WebhookService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<WebhookService>): Promise<WebhookService> {{
    return this.repository.update(id, data);
  }}
}}

